import re, sys
sys.stdout.reconfigure(encoding='utf-8', errors='replace')

# 1. Read existing products-data.js
with open(r'C:\Catalago Prodent\website\js\products-data.js', encoding='utf-8') as f:
    content = f.read()

existing_ids = set(re.findall(r"id:'([^']+)'", content))
print(f"IDs existentes: {len(existing_ids)}")

# 2. Vamasa: extraer entradas del archivo generado
with open(r'C:\Catalago Prodent\website\vamasa_new_products.js', encoding='utf-8') as f:
    vamasa_raw = f.read()

vamasa_lines = [line.strip() for line in vamasa_raw.split('\n')
                if line.strip().startswith("{id:'vamasa-")]
vamasa_block = ""
for line in vamasa_lines:
    m = re.search(r"id:'([^']+)'", line)
    if m and m.group(1) not in existing_ids:
        vamasa_block += "  " + line.rstrip(',') + ",\n"

print(f"Vamasa nuevos: {vamasa_block.count(chr(39)+'vamasa-')}")

