# 5. Check which new IDs already exist and build clean blocks
def filter_block(block_text):
    entries = re.findall(r"\{id:'[^']+'.+?\}", block_text, re.DOTALL)
    result = ""
    added = 0
    for entry in entries:
        m = re.search(r"id:'([^']+)'", entry)
        if m and m.group(1) not in existing_ids:
            result += "  " + entry.strip() + ",\n"
            added += 1
    return result, added

